#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct Point {
	double x, y;
};

double distance(Point const& p1, Point const& p2) {
	return std::sqrt(std::pow(p2.x - p1.x, 2) + std::pow(p2.y - p1.y, 2));
}

// Function to compute the orientation of an ordered triplet (p, q, r)
int orientation(Point &p, Point &q, Point &r) {
    double val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
    if (val == 0.0) return 0; // colinear
    return (val > 0)? 1: 2; // clock or counterclock wise
}

// A utility function to find the next to top in a stack
Point nextToTop(std::vector<Point> &S) {
    Point p = S[S.size() - 2];
    return p;
}

double convexHullPerimeter(const std::vector<Point>& points) {
    if (points.size() < 3) return 0.0; // Edge case: less than 3 points

    int n = points.size();

    // Find the bottom-most point
    int ymin = points[0].y, min = 0;
    for (int i = 1; i < n; ++i) {
        int y = points[i].y;

        if ((y < ymin) || (y == ymin && points[i].x < points[min].x))
            ymin = points[i].y, min = i;
    }

    // Sort points by polar angle with respect to the bottom-most point
    std::swap(points[0], points[min]);
    Point p0 = points[0];

    std::sort(points.begin() + 1, points.end(), [&](Point &p1, Point &p2) {
        int o = orientation(p0, p1, p2);
        if (o == 0)
            return distance(p0, p1) < distance(p0, p2);
        return o == 2;
    });

    // Initialize the convex hull with first three points
    std::vector<Point> S;
    S.push_back(points[0]);
    S.push_back(points[1]);

    for (int i = 2; i < n; ++i) {
        while (S.size() > 1 && orientation(nextToTop(S), S.back(), points[i]) != 2)
            S.pop_back();
        S.push_back(points[i]);
    }

    // Calculate the perimeter of the convex hull
    double perimeter = 0.0;
    #pragma omp parallel for reduction(+ : perimeter) num_threads(4)
    for (int i = 1; i < S.size(); ++i) {
        perimeter += distance(S[i-1], S[i]);
    }
    perimeter += distance(S.back(), S.front()); // Add the last edge to close the polygon

    return perimeter;
}
